import{_ as d,o as e,c as a,a5 as o}from"./chunks/framework.D9Kapg2s.js";const g=JSON.parse('{"title":"使用模式","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/modes.md","filePath":"zh/guide/modes.md"}'),i={name:"zh/guide/modes.md"};function s(r,t,l,c,n,h){return e(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="使用模式" tabindex="-1">使用模式 <a class="header-anchor" href="#使用模式" aria-label="Permalink to &quot;使用模式&quot;">​</a></h1><p>LinguaFlow 提供两种运行模式。<strong>个人使用请优先本地模式</strong>；服务器模式面向多用户与 API 部署，目前仍为预览能力。</p><table tabindex="0"><thead><tr><th>模式</th><th>命令</th><th>默认地址</th><th>推荐场景</th></tr></thead><tbody><tr><td><strong>本地模式</strong></td><td><code>linguaflow</code> / <code>linguaflow local</code></td><td><code>http://127.0.0.1:18080</code></td><td>个人本机、免登录</td></tr><tr><td><strong>服务器模式</strong>（预览）</td><td><code>linguaflow serve</code></td><td><code>http://0.0.0.0:8080</code></td><td>多用户 / 仅 API（功能仍在完善）</td></tr></tbody></table><p>Docker 镜像默认以<strong>服务器模式</strong>监听 <code>8080</code>，与双击二进制进入本地模式不同。详见 <a href="/zh/guide/installation.html">安装部署</a>。</p><h2 id="本地模式" tabindex="-1">本地模式 <a class="header-anchor" href="#本地模式" aria-label="Permalink to &quot;本地模式&quot;">​</a></h2><p>本地模式适用于个人使用，无需登录，数据存储在本机。适合作为默认上手路径。</p><h3 id="启动本地模式" tabindex="-1">启动本地模式 <a class="header-anchor" href="#启动本地模式" aria-label="Permalink to &quot;启动本地模式&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">linguaflow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local</span></span></code></pre></div><p>或者直接双击运行 <code>linguaflow</code>（Windows）/ <code>./linguaflow</code>（Linux/macOS），程序检测到双击启动后会自动进入本地模式。</p><p>启动后会自动打开浏览器访问 <code>http://127.0.0.1:18080</code>。</p><h3 id="本地模式特点" tabindex="-1">本地模式特点 <a class="header-anchor" href="#本地模式特点" aria-label="Permalink to &quot;本地模式特点&quot;">​</a></h3><ul><li><strong>无需登录</strong> — 启动即可使用，前端自动跳过登录和注册页面</li><li><strong>自动打开浏览器</strong> — 默认访问 <code>http://127.0.0.1:18080</code>，可通过 <code>--no-browser</code> 禁用</li><li><strong>嵌入式前端</strong> — 前端静态资源打包在后端二进制中，无需单独部署</li><li><strong>本地数据存储</strong> — SQLite 数据库，数据目录为系统用户配置目录下的 <code>LinguaFlow</code> 文件夹</li><li><strong>端口冲突处理</strong> — 如果端口被占用，自动递增端口号，最多尝试 10 次</li><li><strong>CORS 限制</strong> — 仅允许来自 <code>127.0.0.1</code> 和 <code>localhost</code> 的请求</li></ul><h3 id="本地模式配置" tabindex="-1">本地模式配置 <a class="header-anchor" href="#本地模式配置" aria-label="Permalink to &quot;本地模式配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>描述</th><th>默认值</th></tr></thead><tbody><tr><td><code>--port</code></td><td>监听端口</td><td><code>18080</code></td></tr><tr><td><code>--host</code></td><td>监听地址</td><td><code>127.0.0.1</code></td></tr><tr><td><code>--data-dir</code></td><td>数据目录</td><td><code>UserConfigDir/LinguaFlow</code></td></tr><tr><td><code>--no-browser</code></td><td>不自动打开浏览器</td><td><code>false</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">数据目录说明</p><p><code>UserConfigDir</code> 因操作系统而异：</p><ul><li>Windows: <code>%AppData%</code>（如 <code>C:\\Users\\&lt;用户名&gt;\\AppData\\Roaming</code>）</li><li>macOS: <code>~/Library/Application Support</code></li><li>Linux: <code>~/.config</code>（遵循 <code>XDG_CONFIG_HOME</code>）</li></ul></div><h2 id="服务器模式-预览" tabindex="-1">服务器模式（预览） <a class="header-anchor" href="#服务器模式-预览" aria-label="Permalink to &quot;服务器模式（预览）&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">预览状态</p><p>服务器模式（多用户、权限、组织等）仍在完善中，<strong>不建议用于生产环境或关键业务</strong>。个人翻译请使用 <a href="#本地模式">本地模式</a>。以下说明便于试用与反馈。</p></div><p>服务器模式面向需要登录、多用户或「仅暴露 API」的部署场景。</p><h3 id="启动服务器模式" tabindex="-1">启动服务器模式 <a class="header-anchor" href="#启动服务器模式" aria-label="Permalink to &quot;启动服务器模式&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">linguaflow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><h3 id="服务器模式特点" tabindex="-1">服务器模式特点 <a class="header-anchor" href="#服务器模式特点" aria-label="Permalink to &quot;服务器模式特点&quot;">​</a></h3><ul><li><strong>多用户</strong> — 注册 / 登录（能力仍在迭代）</li><li><strong>JWT 认证</strong> — Access Token 与 Refresh Token</li><li><strong>网络访问</strong> — 默认监听 <code>0.0.0.0</code>（部署时请自行限制暴露面）</li><li><strong>数据库</strong> — 默认 SQLite；可尝试 PostgreSQL（环境变量配置）</li><li><strong>嵌入式 Web UI</strong> — 默认开启；<code>--no-ui</code> 或 <code>LINGUAFLOW_SERVE_UI=false</code> 可仅暴露 API</li></ul><h3 id="服务器模式配置" tabindex="-1">服务器模式配置 <a class="header-anchor" href="#服务器模式配置" aria-label="Permalink to &quot;服务器模式配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>描述</th><th>默认值</th></tr></thead><tbody><tr><td><code>--port</code></td><td>监听端口</td><td><code>8080</code></td></tr><tr><td><code>--host</code></td><td>监听地址</td><td><code>0.0.0.0</code></td></tr><tr><td><code>--data-dir</code></td><td>数据目录</td><td><code>./data</code></td></tr><tr><td><code>--auto-migrate</code></td><td>自动迁移数据库</td><td><code>true</code></td></tr><tr><td><code>--no-ui</code></td><td>关闭嵌入式 Web UI，仅提供 API</td><td><code>false</code></td></tr><tr><td><code>--jwt-secret</code></td><td>覆盖 JWT 签名密钥</td><td>—</td></tr><tr><td><code>--cors-origins</code></td><td>覆盖允许的跨域来源</td><td>—</td></tr></tbody></table><h3 id="管理员配置" tabindex="-1">管理员配置 <a class="header-anchor" href="#管理员配置" aria-label="Permalink to &quot;管理员配置&quot;">​</a></h3><p>服务器模式下，可通过环境变量配置初始管理员账户：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LINGUAFLOW_ADMIN_USERNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">admin</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LINGUAFLOW_ADMIN_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">your-secure-password</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">linguaflow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>如果未设置环境变量，首个注册的用户将自动成为管理员（取决于配置中 <code>registration.auto_admin</code> 的设置）。</p><div class="warning custom-block"><p class="custom-block-title">安全提示</p><p>服务器模式下，请确保：</p><ul><li>使用强密码</li><li>修改默认的 JWT Secret（配置项 <code>server.jwt_secret</code>）</li><li>在生产环境中配置 HTTPS（通过反向代理）</li><li>限制监听地址为内网或配置防火墙</li></ul></div><h2 id="模式对比" tabindex="-1">模式对比 <a class="header-anchor" href="#模式对比" aria-label="Permalink to &quot;模式对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>本地模式</th><th>服务器模式</th></tr></thead><tbody><tr><td>CLI 命令</td><td><code>linguaflow local</code></td><td><code>linguaflow serve</code></td></tr><tr><td>用户认证</td><td>自动认证（跳过 JWT）</td><td>JWT Token 认证</td></tr><tr><td>多用户</td><td>单用户（<code>local</code> 用户）</td><td>多租户</td></tr><tr><td>用户注册</td><td>不支持</td><td>默认开放</td></tr><tr><td>默认端口</td><td><code>18080</code></td><td><code>8080</code></td></tr><tr><td>默认监听</td><td><code>127.0.0.1</code></td><td><code>0.0.0.0</code></td></tr><tr><td>数据目录</td><td><code>UserConfigDir/LinguaFlow</code></td><td><code>./data</code></td></tr><tr><td>数据库</td><td>仅 SQLite</td><td>SQLite / PostgreSQL</td></tr><tr><td>前端资源</td><td>嵌入在二进制中</td><td>默认嵌入，可 <code>--no-ui</code> 关闭</td></tr><tr><td>CORS 策略</td><td>仅 localhost</td><td>可配置（默认 <code>*</code>）</td></tr><tr><td>自动打开浏览器</td><td>是</td><td>否</td></tr><tr><td>双击启动</td><td>自动进入本地模式</td><td>不支持</td></tr><tr><td>成熟度</td><td>推荐日常使用</td><td>预览，功能仍在完善</td></tr><tr><td>适用场景</td><td>个人使用</td><td>试用多用户 / API 服务</td></tr></tbody></table><h2 id="界面上的差异" tabindex="-1">界面上的差异 <a class="header-anchor" href="#界面上的差异" aria-label="Permalink to &quot;界面上的差异&quot;">​</a></h2><ul><li><strong>本地模式</strong>：免登录直接进入主界面，顶部通常有「本地模式」标识</li><li><strong>服务器模式</strong>：需注册/登录；可切换服务端地址</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/zh/guide/getting-started.html">快速开始 · Web</a> — 本地模式最短路径</li><li><a href="/zh/guide/installation.html">安装部署</a> — Docker 与数据目录</li><li><a href="/zh/guide/configuration.html">配置文件与环境变量</a> — 环境变量与配置文件</li><li><a href="/zh/guide/cli.html">CLI 命令参考</a> — 全部子命令</li></ul>`,35)])])}const u=d(i,[["render",s]]);export{g as __pageData,u as default};
